import React from "react"
import '../collapse.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import dayGridPlugin from '@fullcalendar/daygrid' // a plugin!
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import Moment from 'moment'
import Collapsible from "react-collapsible"

var evalValue = []
//var checkedEval = []
var buildEvaluation = []
var indexCheckbox = 0

class Evalulation extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], teamValue: "", screen: 0, dateStr: "", teamId: "", incompleteEval: [], createEvalResult: [], disableSubmitButton: true
        };

    }


        componentDidMount() {


            const search = this.props.location.search;
            const params = new URLSearchParams(search);
            const programID = params.get('programid');

            var query = ""
            if (programID != null) {
              query = "?programid=" + programID 
            }

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = `http://localhost:9000/eval`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                this.setState({screen: 1})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }


          handleDidMount = () => {

            for (let x in this.state.results) {
              var inTomorrow = true
              //content.push(<div>{this.state.results[x].eventDate}</div>)
              //content.push(<div><hr></hr></div>)
              //each team
              for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                        inTomorrow = false
                    }
                  }
              } 
              if (!inTomorrow) {
                var findDate = document.querySelector('[data-date="' + this.state.results[x].eventDate +'"]')
                if (findDate != null) {
                  var dateNumber = findDate.getElementsByClassName("fc-daygrid-day-number")
                  for (var i = 0; i < dateNumber.length; i++) {
                    dateNumber[i].style.color = "red"; 
                  }
                }
              }
            }

/*
            for (let x in this.state.results) {
              var inTomorrow = true
              //content.push(<div>{this.state.results[x].eventDate}</div>)
              //content.push(<div><hr></hr></div>)
              //each team
              for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                        inTomorrow = false
                    }
                  }
              } 
              if (!inTomorrow) {
                console.log(this.state.results[x].eventDate)

                var findDate = document.querySelector('[data-date="' + this.state.results[x].eventDate +'"]')
                var dateNumber = findDate.getElementsByClassName("fc-daygrid-day-number")
                for (var i = 0; i < dateNumber.length; i++) {
                  dateNumber[i].style.color = "red"; 
                }

              }

            }  
*/

          }


          createEval = (buildRequest) => {
            //console.log(buildRequest)
            this.setState({screen: 0});

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');


            var backUrl = `http://localhost:9000/medhubcreateeval`
            fetch(backUrl, {
              "method": "POST",
              headers: headers,
              body: JSON.stringify({evals: buildRequest})

            })
            .then(response => response.json())
            .then(response => {
              //console.log(response);
              this.setState({createEvalResult: response})
              //this.setState({results: response})
              //this.setState({incompleteEval: response})
              //this.setState({stage: 1});
              //_forEach(response, d => console.log(d.name))
              //console.log(this.state.results)
              var dateTeam = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].data.filter(Record => Record.id === this.state.teamId)[0]
              this.callIncomplete(dateTeam);
            })
            .catch(err => {
              console.log(err);
            });



          }



          callIncomplete = (teamInfo) => {

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var userIDs = []
            if (teamInfo.userID != 0) {
              userIDs.push(teamInfo.userID)
            }

            for (let y in teamInfo.members) {
              if (teamInfo.members[y].userID != 0){
                userIDs.push(teamInfo.members[y].userID)
              }
            }


            var backUrl = `http://localhost:9000/medhubincomplete`
            fetch(backUrl, {
              "method": "POST",
              headers: headers,
              body: JSON.stringify({userIDs: userIDs})

            })
            .then(response => response.json())
            .then(response => {
              //console.log(response);
              //this.setState({results: response})
              this.setState({incompleteEval: response})
              this.setState({screen: 3})
              //_forEach(response, d => console.log(d.name))
              //console.log(this.state.results)
            })
            .catch(err => {
              console.log(err);
            });

          }


          handleEventClick = (arg) => { // bind with an arrow function
            //alert(arg.dateStr)
            //console.log(arg)
            this.setState({dateStr: arg.event.startStr})
            this.setState({screen: 2})
          }


          handleDateClick = (arg) => { // bind with an arrow function
            //alert(arg.dateStr)
            //console.log(arg)
            this.setState({dateStr: arg.dateStr})
            this.setState({screen: 2})
          }


          goBackFirstScreen = () => {
            this.setState({screen: 1});
          }

          goBackSecondScreen = () => {
            this.setState({screen: 2});
          }

          goBack = () => {
            this.setState({dateStr: Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD")})
            //console.log(Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD"))
            this.setState({screen: 2})
          }


          goForward = () => {
            this.setState({dateStr: Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD")})
            this.setState({screen: 2})
          }


          goCreateEvaluation = (teamId) => {
            this.setState({screen: 0})
            this.setState({teamId: teamId})
            this.setState({createEvalResult: []})
            var dateTeam = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].data.filter(Record => Record.id === teamId)[0]

            //console.log(dateTeam)
            this.callIncomplete(dateTeam)


          }


          handleOnChange = (checkboxID) => {

            //console.log(document.getElementById("123").value.evaluationID)
           //document.getElementById("submitButton").disabled = false

            var noSelect = true
            var i = 0
            while (i < indexCheckbox) {
              //console.log(document.getElementById("eval"+i).checked)
              if (document.getElementById("eval"+i).checked) {
                noSelect = false
              }
              i += 1
            }


            this.setState({disableSubmitButton: noSelect})
            //console.log(evalValue)
          }

          handleSubmitEval = () => {

            //console.log(evalValue)
            var buildRequest = []
            var i = 0
            while (i < indexCheckbox) {
              //console.log(document.getElementById("eval"+i).checked)
              if (document.getElementById("eval"+i).checked) {
                buildRequest.push(evalValue.filter(Record => Record.checkboxID === i)[0])
              }
              i += 1
            }
            this.createEval(buildRequest)
           //console.log(buildRequest)

            //console.log("submit")
          }


          makeCheckBox = (evalId,evalType,evaluator_userID,evauluatee_userID,title) => {
            var checkboxValue = {"checkboxID": indexCheckbox,"evaluationID":evalId,"eval_type":evalType,"evaluator_userID":evaluator_userID,"programID":1350,"evaluatee_userID":evauluatee_userID,"title":title}
            evalValue.push(checkboxValue)
            var checkboxID = "eval" + indexCheckbox
            //checkedEval.push(indexCheckbox)
            indexCheckbox += 1

            buildEvaluation.push(<div><input onChange={() => this.handleOnChange(indexCheckbox)} id={checkboxID} type="checkbox"/><label>{title}</label></div>)


            //console.log(evalValue)

          }






          render() {


            var todayDate = "Loading ..."
            var content = []
            var events = []




            if (this.state.screen === 1) {

              todayDate = ""
              for (let x in this.state.results) {
                var inTomorrow = true 
                for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                      inTomorrow = false
                    }
                  }
                }
                if (!inTomorrow) {
                  events.push({id: "", groupId: this.state.results[x].groupId,title: " - Rotation Change - ",  date: this.state.results[x].eventDate, color: "#FF7F7F", textColor: "black" })
                }
              }


              content.push(                 <FullCalendar
                plugins={[ dayGridPlugin, interactionPlugin ]}
                initialView="dayGridMonth"
                events={events}
                eventClick={this.handleEventClick}
                dateClick={this.handleDateClick}
                eventOrder="id"
                eventDidMount={this.handleDidMount}

              />)



            }


            if (this.state.screen === 3) {
              todayDate = ""
              var dateTeam = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].data.filter(Record => Record.id === this.state.teamId)[0]
              //console.log(dateTeam)
              content.push(<div> <button onClick={() => this.goBackSecondScreen()} style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow"}}>Go Back</button><h3>Date: {dateTeam.date}</h3></div>)

              content.push(<div style={{color: "green", marginBottom: "5px", fontStyle: "bold"}}><h3>{dateTeam.assignment}</h3></div>)
              content.push(<hr></hr>)
              content.push(<div></div>)

              buildEvaluation = []


              var facuColor = "black"
              if (!dateTeam.inTomorrow) {
                facuColor = "red"
              }


              var residentsContent = []
              evalValue = []

              indexCheckbox = 0

              for (let y in dateTeam.members) {

                var colorRes = "black"
                if (!dateTeam.members[y].inTomorrow) {
                  colorRes = "red"
                }



                //residentsContent.push(<div style={{marginLeft: '10px', color: colorRes}}>- {dateTeam.members[y].name} * medHubID: ({dateTeam.members[y].userID}) - programID: {dateTeam.members[y].programID}</div>)

                var noEval = true
                var addResInternToFacultyEval = false

                var typeString = ""
                if (dateTeam.members[y].resident) {
                  typeString = " - resident"
                  if (!dateTeam.inTomorrow || !dateTeam.members[y].inTomorrow) {

                    this.makeCheckBox(5735,5,dateTeam.userID,dateTeam.members[y].userID,dateTeam.name + " => " + dateTeam.members[y].name + " IM - UC Wards (Faculty of Resident - New)")
                    /*
                    var checkboxValue = {"checkboxID": indexCheckbox,"evaluationID":5735,"eval_type":5,"evaluator_userID":dateTeam.userID,"programID":1350,"evaluatee_userID":dateTeam.members[y].userID,"title":dateTeam.name + " => " + dateTeam.members[y].name + " IM - UC Wards (Faculty of Resident - New)"}
                    evalValue.push(checkboxValue)
                    let checkboxID = "eval" + indexCheckbox
                    checkedEval.push(indexCheckbox)
                    indexCheckbox += 1
                    buildEvaluation.push(<div><input checked="true" onChange={() => this.handleOnChange(indexCheckbox)} id={{checkboxID}} type="checkbox"/><label>{dateTeam.name + " => " + dateTeam.members[y].name + " IM - UC Wards (Faculty of Resident - New)"}</label></div>)
                    */
                    addResInternToFacultyEval = true
                  } 
                }
                if (dateTeam.members[y].intern) {
                  typeString = " - intern"
                  if (!dateTeam.inTomorrow || !dateTeam.members[y].inTomorrow) {
                    this.makeCheckBox(5734,5,dateTeam.userID,dateTeam.members[y].userID,dateTeam.name + " => " + dateTeam.members[y].name + " IM - UC Wards (Faculty of Intern - New)")
                    /*
                    var checkboxValue = {"checkboxID": indexCheckbox,"evaluationID":5734,"eval_type":5,"evaluator_userID":dateTeam.userID,"programID":1350,"evaluatee_userID":dateTeam.members[y].userID,"title":dateTeam.name + " => " + dateTeam.members[y].name + " IM - UC Wards (Faculty of Intern - New)"}
                    evalValue.push(checkboxValue)
                    let checkboxID = "eval" + indexCheckbox
                    checkedEval.push(indexCheckbox)
                    indexCheckbox += 1
                    buildEvaluation.push(<div><input checked="true" onChange={() => this.handleOnChange(indexCheckbox)} id={{checkboxID}} type="checkbox"/><label>{dateTeam.name + " => " + dateTeam.members[y].name + " IM - UC Wards (Faculty of Intern - New)"}</label></div>)
